import React, { useState, useEffect } from 'react';
import './App.css';
import AOS from 'aos';
import 'aos/dist/aos.css';
import Lenis from '@studio-freight/lenis';

import { RingLoader } from 'react-spinners';
import GradientWrapper from './GradientWrapper';
import { faAngleDown } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Navbar from './components/Navbar';
import FirstSection from './components/FirstSection';
import SecondSection from './components/SecondSection';
import ThirdSection from './components/ThirdSection';
import FourthSection from './components/FourthSection';
import ButtonsHolder from './components/ButtonsHolder';
import Title from './components/Title';

function App() {
  const [loading, setLoading] = useState(true);

  // Simulate loading for 1 second
  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 2500);

    return () => clearTimeout(timer);
  }, []);

  // Initialize Lenis
  const lenis = new Lenis();

  lenis.on('scroll', (e) => {
    console.log(e);
  });

  function raf(time) {
    lenis.raf(time);
    requestAnimationFrame(raf);
  }

  requestAnimationFrame(raf);

  AOS.init();

  return (
    <div className="App">
      <div className={`loading-spinner ${loading ? '' : 'hidden'}`}>
        <h1 style={{ fontSize: '50px' }}>Turning the lights on...</h1>
        <lottie-player
          src="https://lottie.host/11e62f91-9838-4358-9af9-8c6bc78495d0/VP7IYRaKzo.json"
          background="#fff"
          speed="1"
          style={{ width: '300px', height: '300px' }} // Fix: Convert style to an object
          loop
          controls
          autoplay
          direction="1"
          mode="normal"
        ></lottie-player>
      </div>
      {!loading && (
        <>
          <Navbar />
          <GradientWrapper />
          <div className="rowmenucontainer">
            <div className="arrow bounce">
              <FontAwesomeIcon icon={faAngleDown} /> {/* Fix: Remove i tag */}
            </div>
            <Title />
            <ButtonsHolder />
          </div>
          <div className="sections">
            <FirstSection />
            <SecondSection />
            <ThirdSection />
            <FourthSection />
          </div>
        </>
      )}
    </div>
  );
}

export default App;
